#include "Connect_Wed.h"
#include <WiFi.h>
#include <EEPROM.h>
#include <functional> // Cần cho std::bind

#define EEPROM_SIZE 128

// --- CONSTRUCTOR ---
Connect_Wed::Connect_Wed(const char* apName) {
    _ap_ssid = apName;
    _server = new WebServer(80);
}

// --- HÀM PUBLIC ---
void Connect_Wed::begin() {
    Serial.begin(115200);
    Serial.println("\n[Connect_Wed] Khoi dong...");

    EEPROM.begin(EEPROM_SIZE);

    if (!_autoConnectFromEEPROM()) {
        _setupAP();
    }

    _server->on("/", HTTP_GET, std::bind(&Connect_Wed::_handleRoot, this));
    _server->on("/connect", HTTP_POST, std::bind(&Connect_Wed::_handleConnect, this));
    
    _server->begin();
    Serial.println("[Connect_Wed] Web Server da bat dau.");
}

void Connect_Wed::loop() {
    _server->handleClient();
}

/**
 * @brief Xóa thông tin WiFi đã lưu trong EEPROM.
 */
void Connect_Wed::RST_ERROOM() {
    Serial.println("[Connect_Wed] Dang xoa thong tin WiFi trong EEPROM...");
    // Ghi giá trị 0 vào từng byte của EEPROM
    for (int i = 0; i < EEPROM_SIZE; i++) {
        EEPROM.write(i, 0);
    }
    // Lưu thay đổi
    if (EEPROM.commit()) {
        Serial.println("[Connect_Wed] Xoa EEPROM thanh cong!");
    } else {
        Serial.println("[Connect_Wed] Xoa EEPROM that bai!");
    }
}


// --- CÁC HÀM PRIVATE ---
void Connect_Wed::_setupAP() {
    WiFi.mode(WIFI_AP);
    WiFi.softAP(_ap_ssid);
    Serial.print("[Connect_Wed] Access Point da duoc tao: "); Serial.println(_ap_ssid);
    Serial.print("[Connect_Wed] Dia chi IP cua AP: "); Serial.println(WiFi.softAPIP());
}

bool Connect_Wed::_autoConnectFromEEPROM() {
    String saved_ssid = _readStringFromEEPROM(0);
    String saved_pass = _readStringFromEEPROM(64);

    if (saved_ssid.length() > 0) {
        Serial.println("[Connect_Wed] Tim thay thong tin WiFi da luu.");
        WiFi.mode(WIFI_STA);
        WiFi.begin(saved_ssid.c_str(), saved_pass.c_str());
        
        Serial.print("[Connect_Wed] Dang thu ket noi tu dong...");
        int attempts = 0;
        while (WiFi.status() != WL_CONNECTED && attempts < 20) {
            delay(500);
            Serial.print(".");
            attempts++;
        }
        if (WiFi.status() == WL_CONNECTED) {
            Serial.println("\n[Connect_Wed] Ket noi tu dong thanh cong!");
            Serial.print("[Connect_Wed] Dia chi IP: "); Serial.println(WiFi.localIP());
            return true;
        } else {
            Serial.println("\n[Connect_Wed] Ket noi tu dong that bai.");
            return false;
        }
    }
    return false;
}

void Connect_Wed::_handleRoot() {
    _server->send(200, "text/html", _buildHtmlPage());
}

void Connect_Wed::_handleConnect() {
    String ssid = _server->arg("ssid");
    String password = _server->arg("password");

    // Thử kết nối với WiFi mới
    WiFi.begin(ssid.c_str(), password.c_str());

    Serial.print("[Connect_Wed] Dang ket noi toi mang moi...");
    int attempts = 0;
    // Chờ kết nối (khoảng 15 giây)
    while (WiFi.status() != WL_CONNECTED && attempts < 30) {
        delay(500);
        Serial.print(".");
        attempts++;
    }

    // --- KIỂM TRA KẾT QUẢ ---
    if (WiFi.status() == WL_CONNECTED) {
        // === TRƯỜNG HỢP 1: THÀNH CÔNG ===
        Serial.println("\n[Connect_Wed] Ket noi thanh cong!");
        Serial.println("[Connect_Wed] Luu thong tin vao EEPROM...");
        
        // 1. Ghi dữ liệu vào bộ đệm
        _writeStringToEEPROM(0, ssid);
        _writeStringToEEPROM(64, password);
        
        // 2. Lưu thực sự vào Flash
        if (EEPROM.commit()) {
             Serial.println("[Connect_Wed] Luu EEPROM thanh cong.");
        }

        // 3. Gửi thông báo cho người dùng trên Web
        String response = "<!DOCTYPE html><html><head><meta charset='UTF-8'></head>";
        response += "<body><h1 style='color:green;'>Ket noi thanh cong!</h1>";
        response += "<p>Da luu mang: <strong>" + ssid + "</strong></p>";
        response += "<p>Thiet bi se khoi dong lai sau 3 giay...</p></body></html>";
        _server->send(200, "text/html", response);
        
        // 4. Chờ một chút để gửi xong phản hồi
        delay(2000); 
        
        // 5. Tự động Reset
        ESP.restart(); 

    } else {
        // === TRƯỜNG HỢP 2: THẤT BẠI (Sai mật khẩu hoặc không tìm thấy mạng) ===
        Serial.println("\n[Connect_Wed] Ket noi that bai!");
        
        // Quay trở lại trang nhập mật khẩu
        _server->sendHeader("Location", "/");
        _server->send(303);
    }
}


